const req = $input.item.json;
let docnum = '';
if (req.query && req.query.docnum) {
  docnum = req.query.docnum;
} else {
  const url = req.headers && req.headers['x-original-url'] ? req.headers['x-original-url'] : (req.url || '');
  const parts = url.split('/');
  const lastPart = parts[parts.length - 1];
  docnum = lastPart ? lastPart.split('?')[0] : '';
}
if (!docnum || docnum === 'po' || docnum === 'undefined') {
  return { json: { _error: true, success: false, message: '请提供采购订单号' } };
}
// SAP DocNum为INT类型，过滤非数字输入
if (!/^\d+$/.test(docnum)) {
  return { json: { _error: true, success: false, message: '采购订单号必须为纯数字: ' + docnum } };
}
// 安全加固: 强制转为整数字符串，纵深防御
docnum = String(parseInt(docnum, 10));
if (docnum === 'NaN') {
  return { json: { _error: true, success: false, message: '单号解析失败' } };
}
return { json: { _error: false, docnum: docnum } };

// 获取SAP结果 (try-catch保护: MS SQL凭证可能未配置)
let sapRows = [];
try {
  sapRows = $('SAP查询').all().filter(r => !r.json.set_config);
} catch(e) {
  return { json: { success: false, message: 'SAP查询失败，请检查MS SQL凭证配置: ' + e.message } };
}

const wmsRows = $('PG WMS').all();

if (!sapRows || sapRows.length === 0 || !sapRows[0].json.DocNum) {
  return { json: { success: false, error_type: 'not_found', message: '未找到该订单' } };
}

const first = sapRows[0].json;
// 去重: PG WMS 多行导致 SAP 查询重复执行，按 LineNum 去重
const lineMap = {};
sapRows.forEach(r => { if (r.json.LineNum != null) lineMap[r.json.LineNum] = r; });
const dedupedRows = Object.values(lineMap);
const lines = dedupedRows.map(r => ({
  lineNum: r.json.LineNum,
  itemCode: r.json.ItemCode,
  itemName: r.json.ItemName || '',
  quantity: parseFloat(r.json.Quantity) || 0,
  openQty: parseFloat(r.json.OpenQty) || 0,
  lineStatus: r.json.LineStatus || 'O',
  uom: r.json.uom || '',
  whsCode: r.json.WhsCode || '',
  manBtchNum: r.json.ManBtchNum || 'N'
}));

const lineReceipts = {};
const transactions = [];
let docWmsStatus = 'pending';
for (const r of wmsRows) {
  if (r.json.doc_wms_status) docWmsStatus = r.json.doc_wms_status;
  if (r.json.id) {
    const ln = r.json.line_num;
    if (ln !== null && ln !== undefined) {
      lineReceipts[ln] = (lineReceipts[ln] || 0) + parseFloat(r.json.quantity || 0);
    }
    transactions.push({
      transaction_time: r.json.transaction_time,
      item_code: r.json.item_code || '',
      item_name: r.json.item_name || '',
      quantity: parseFloat(r.json.quantity),
      performed_by: r.json.performed_by,
      remarks: r.json.remarks || ''
    });
  }
}

return { json: {
  success: true,
  sap_order: {
    docNum: String(first.DocNum),
    docEntry: first.DocEntry,
    cardCode: first.CardCode || '',
    cardName: first.CardName || '',
    docDueDate: first.DocDueDate,
    docStatus: first.DocStatus || 'O',
    lines: lines
  },
  wms_history: {
    wms_status: docWmsStatus,
    lineReceipts: lineReceipts,
    transactions: transactions
  }
}};

// V19.3: Prepare Prefill - SAP 全量行预填入 WMS
const data = $('Merge Data').item.json;

// 查询失败或无行时跳过预填
if (!data.success || !data.sap_order || !data.sap_order.lines || data.sap_order.lines.length === 0) {
  return { json: { _prefillSql: 'SELECT 1' } };
}

const order = data.sap_order;
const cc = $env.DP_COMPANY_CODE;
const user = ($('Webhook').item.json.query && $('Webhook').item.json.query.user) || 'SYSTEM';

function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  let s = String(v).substring(0, 500).replace(/�/g, '');
  return "'" + s.replace(/\\/g, '\\\\').replace(/'/g, "''") + "'";
}
function escDate(v) {
  if (!v) return 'NULL';
  const d = new Date(v);
  return isNaN(d.getTime()) ? 'NULL' : "'" + d.toISOString().slice(0,10) + "'";
}

const whsCode = order.lines[0].whsCode || '';

const lineVals = order.lines.map(l =>
  '((SELECT id FROM doc), ' + l.lineNum + ', ' +
  esc(l.itemCode) + ', ' + esc(l.itemName) + ', ' + esc(l.uom) + ', ' +
  (parseFloat(l.openQty) || 0) + ", 0, " + esc(l.whsCode) + ", 'pending', 'pending')"
).join(',\n  ');

const sql = `WITH doc AS (
  INSERT INTO wms.wms_documents
    (company_code, doc_type, doc_number, sap_doc_num, sap_doc_entry,
     status, wms_status, business_partner, bp_name,
     warehouse_code, created_by, doc_date, due_date)
  VALUES (${esc(cc)}, 'PO', ${esc(order.docNum)}, ${esc(order.docNum)}, ${order.docEntry || 0},
     'draft', 'pending', ${esc(order.cardCode)}, ${esc(order.cardName)},
     ${esc(whsCode)}, ${esc(user)}, CURRENT_DATE, ${escDate(order.docDueDate)})
  ON CONFLICT (company_code, doc_type, doc_number) DO UPDATE SET
    sap_doc_entry = EXCLUDED.sap_doc_entry,
    created_by = CASE WHEN wms.wms_documents.created_by = 'SYSTEM' THEN EXCLUDED.created_by ELSE wms.wms_documents.created_by END,
    business_partner = EXCLUDED.business_partner,
    bp_name = EXCLUDED.bp_name,
    due_date = EXCLUDED.due_date,
    wms_status = wms.wms_documents.wms_status,
    status = wms.wms_documents.status
  RETURNING id
)
INSERT INTO wms.wms_document_lines
  (document_id, line_num, item_code, item_name, uom,
   planned_qty, actual_qty, warehouse_code, status, wms_status)
VALUES
  ${lineVals}
ON CONFLICT (document_id, line_num) DO UPDATE SET
  item_name = EXCLUDED.item_name,
  uom = EXCLUDED.uom,
  planned_qty = EXCLUDED.planned_qty,
  warehouse_code = EXCLUDED.warehouse_code;`;

return { json: { _prefillSql: sql } };
